    @Id @GeneratedValue(strategy = GenerationType.UUID)
    val id: String = "",
    @Column(nullable = false) val callerId: String,
    @Column(nullable = false) val receiverId: String,
    @Enumerated(EnumType.STRING) @Column(nullable = false)
    var status: CallStatus = CallStatus.INITIATED,
    @Column val startedAt: LocalDateTime? = null,
    @Column var endedAt: LocalDateTime? = null,
    @Column var durationSeconds: Long? = null,
    @Column(nullable = false) val createdAt: LocalDateTime = LocalDateTime.now()
