### 2. 테스트 코드

**`CallServiceTest.kt`** - 핵심 버그 재현 포함
```kotlin
package com.maum.backend.call.service

import com.maum.backend.call.domain.entity.CallEntity
import com.maum.backend.call.domain.entity.CallStatus
import com.maum.backend.call.domain.repository.CallRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.time.LocalDateTime
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // ─────────────────────────────────────────────
    // initiateCall
    // ─────────────────────────────────────────────

    @Test
    fun `should initiate call when caller and receiver are different users`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val savedCall = CallEntity(
            id = "call-1",
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.RINGING,
            startedAt = LocalDateTime.now()
        )
        whenever(callRepository.findActiveCallByUserId(callerId)).thenReturn(null)
        whenever(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.initiateCall(callerId, receiverId)

        // then
        assertThat(result.callerId).isEqualTo(callerId)
        assertThat(result.receiverId).isEqualTo(receiverId)
        assertThat(result.status).isEqualTo(CallStatus.RINGING)
        verify(callRepository).save(any())
    }

    @Test
    fun `should throw when caller tries to call themselves`() {
        // given - [버그 재현] 자기 자신에게 전화
        val userId = "user-A"

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            callService.initiateCall(userId, userId)
        }
        assertThat(exception.message).contains("자기 자신에게 전화할 수 없습니다")
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw when caller already has an active call`() {
        // given - [버그 재현] 이미 통화 중인 사용자의 재발신
        val callerId = "user-A"
        val existingCall = CallEntity(
            id = "existing-call",
            callerId = callerId,
            receiverId = "user-C",
            status = CallStatus.ANSWERED
        )
        whenever(callRepository.findActiveCallByUserId(callerId)).thenReturn(existingCall)

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            callService.initiateCall(callerId, "user-B")
        }
        assertThat(exception.message).contains("이미 진행 중인 통화가 있습니다")
        verify(callRepository, never()).save(any())
    }

    // ─────────────────────────────────────────────
    // answerCall
    // ─────────────────────────────────────────────

    @Test
    fun `should answer call when receiver accepts ringing call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val ringingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.RINGING
        )
        val answeredCall = ringingCall.apply { status = CallStatus.ANSWERED }

        whenever(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))
        whenever(callRepository.save(any())).thenReturn(answeredCall)

        // when
        val result = callService.answerCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ANSWERED)
        verify(callRepository).save(any())
    }

    @Test
    fun `should throw when non-receiver tries to answer call`() {
        // given - [버그 재현] 수신자가 아닌 사용자가 수락 시도
        val callId = "call-1"
        val ringingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.RINGING
        )
        whenever(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            callService.answerCall(callId, "user-C") // 수신자가 아닌 사람
        }
        assertThat(exception.message).contains("통화 수신자가 아닙니다")
    }

    @Test
    fun `should throw when answering already answered call`() {
        // given - [버그 재현] 이미 연결된 통화에 재수락 시도
        val callId = "call-1"
        val answeredCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ANSWERED  // 이미 ANSWERED
        )
        whenever(callRepository.findById(callId)).thenReturn(Optional.of(answeredCall))

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            callService.answerCall(callId, "user-B")
        }
        assertThat(exception.message).contains("수락 가능한 상태가 아닙니다")
    }

    @Test
    fun `should throw when call not found on answer`() {
        // given
        whenever(callRepository.findById("non-existent")).thenReturn(Optional.empty())

        // when & then
        assertThrows<NoSuchElementException> {
            callService.answerCall("non-existent", "user-B")
        }
    }

    // ─────────────────────────────────────────────
    // endCall
    // ─────────────────────────────────────────────

    @Test
    fun `should end call and calculate duration when startedAt is present`() {
        // given
        val callId = "call-1"
        val startedAt = LocalDateTime.now().minusMinutes(5)
        val call = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ANSWERED,
            startedAt = startedAt
        )
        whenever(callRepository.findById(callId)).thenReturn(Optional.of(call))
        whenever(callRepository.save(any())).thenAnswer { it.arguments[0] as CallEntity }

        // when
        val result = callService.endCall(callId, "user-A")

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED)
        assertThat(result.endedAt).isNotNull()
        assertThat(result.durationSeconds).isGreaterThanOrEqualTo(300L) // 5분 이상
    }

    @Test
    fun `should end call with null duration when startedAt is null`() {
        // given - [버그 재현] startedAt 없이 종료 시 NPE 방지
        val callId = "call-1"
        val call = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.RINGING,
            startedAt = null  // RINGING 상태에서 강제 종료
        )
        whenever(callRepository.findById(callId)).thenReturn(Optional.of(call))
        whenever(callRepository.save(any())).thenAnswer { it.arguments[0] as CallEntity }

        // when
        val result = callService.endCall(callId, "user-A")

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED)
        assertThat(result.durationSeconds).isNull() // NPE 없이 null 처리
    }

    @Test
    fun `should throw when non-participant tries to end call`() {
        // given - [버그 재현] 통화 참여자가 아닌 사람이 종료 시도
        val call = CallEntity(
            id = "call-1",
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ANSWERED
        )
        whenever(callRepository.findById("call-1")).thenReturn(Optional.of(call))

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            callService.endCall("call-1", "user-C")
        }
        assertThat(exception.message).contains("통화 참여자가 아닙니다")
    }

    @Test
    fun `should throw when ending already ended call`() {
        // given - [버그 재현] 이미 종료된 통화를 다시 종료 시도 (중복 종료)
        val call = CallEntity(
            id = "call-1",
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ENDED
        )
        whenever(callRepository.findById("call-1")).thenReturn(Optional.of(call))

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            callService.endCall("call-1", "user-A")
        }
        assertThat(exception.message).contains("이미 종료된 통화입니다")
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw when ending rejected call`() {
        // given
        val call = CallEntity(
            id = "call-1",
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.REJECTED
        )
        whenever(callRepository.findById("call-1")).thenReturn(Optional.of(call))

        // when & then
        assertThrows<IllegalArgumentException> {
            callService.endCall("call-1", "user-A")
        }
    }

    // ─────────────────────────────────────────────
    // rejectCall
    // ─────────────────────────────────────────────

    @Test
    fun `should reject call when receiver declines ringing call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val ringingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.RINGING
        )
        whenever(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))
        whenever(callRepository.save(any())).thenAnswer { it.arguments[0] as CallEntity }

        // when
        val result = callService.rejectCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.REJECTED)
        assertThat(result.endedAt).isNotNull()
    }

    @Test
    fun `should throw when rejecting non-ringing call`() {
        // given - [버그 재현] ANSWERED 상태에서 거절 시도
        val call = CallEntity(
            id = "call-1",
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ANSWERED
        )
