```kotlin
package com.maum.backend.call.service

import com.maum.backend.call.domain.entity.CallEntity
import com.maum.backend.call.domain.entity.CallStatus
import com.maum.backend.call.domain.repository.CallRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import java.time.LocalDateTime

@Service
@Transactional
class CallService(
    private val callRepository: CallRepository
) {
    fun initiateCall(callerId: String, receiverId: String): CallEntity {
        // [버그 지점 1] 자기 자신에게 전화 가능 → 검증 필요
        require(callerId != receiverId) { "자기 자신에게 전화할 수 없습니다" }

        // [버그 지점 2] 이미 통화 중인 사용자가 발신 가능 → 검증 필요
        val existingCall = callRepository.findActiveCallByUserId(callerId)
        require(existingCall == null) { "이미 진행 중인 통화가 있습니다" }

        val call = CallEntity(
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.RINGING,
            startedAt = LocalDateTime.now()
        )
        return callRepository.save(call)
    }

    fun answerCall(callId: String, receiverId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        // [버그 지점 3] 수신자 본인 검증 누락 가능
        require(call.receiverId == receiverId) { "통화 수신자가 아닙니다" }
        // [버그 지점 4] RINGING 상태가 아닌 통화에 ANSWER 시도
        require(call.status == CallStatus.RINGING) {
            "수락 가능한 상태가 아닙니다: ${call.status}"
        }

        call.status = CallStatus.ANSWERED
        return callRepository.save(call)
    }

    fun endCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        require(call.callerId == userId || call.receiverId == userId) {
            "통화 참여자가 아닙니다"
        }
        // [버그 지점 5] 이미 종료된 통화를 다시 종료 시도
        require(call.status !in listOf(CallStatus.ENDED, CallStatus.MISSED, CallStatus.REJECTED)) {
            "이미 종료된 통화입니다: ${call.status}"
        }

        val now = LocalDateTime.now()
        call.status = CallStatus.ENDED
        call.endedAt = now
        // [버그 지점 6] 통화 시간 계산 시 startedAt null 처리 누락
        call.durationSeconds = call.startedAt?.let {
            java.time.Duration.between(it, now).seconds
        }
        return callRepository.save(call)
    }

    fun rejectCall(callId: String, receiverId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        require(call.receiverId == receiverId) { "통화 수신자가 아닙니다" }
        require(call.status == CallStatus.RINGING) {
            "거절 가능한 상태가 아닙니다: ${call.status}"
        }

        call.status = CallStatus.REJECTED
        call.endedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    @Transactional(readOnly = true)
    fun getActiveCall(userId: String): CallEntity? {
        return callRepository.findActiveCallByUserId(userId)
    }

    @Transactional(readOnly = true)
    fun getCallHistory(userId: String): List<CallEntity> {
        return (callRepository.findByCallerId(userId) + callRepository.findByReceiverId(userId))
            .distinctBy { it.id }
            .sortedByDescending { it.createdAt }
    }
}
