        // given - [버그 재현] caller+receiver 조회 시 중복 통화 발생 가능
        val userId = "user-A"
        val call1 = CallEntity(
            id = "call-1",
            callerId = userId,
            receiverId = "user-B",
            status = CallStatus.ENDED,
            createdAt = LocalDateTime.now().minusHours(2)
        )
        val call2 = CallEntity(
            id = "call-2",
            callerId = "user-C",
            receiverId = userId,
            status = CallStatus.ENDED,
            createdAt = LocalDateTime.now().minusHours(1)
        )
        // call1이 양쪽 조회에서 중복될 수 있는 케이스
        whenever(callRepository.findByCallerId(userId)).thenReturn(listOf(call1))
        whenever(callRepository.findByReceiverId(userId)).thenReturn(listOf(call2))

        // when
        val result = callService.getCallHistory(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result[0].id).isEqualTo("call-2") // 최신순 정렬
        assertThat(result[1].id).isEqualTo("call-1")
    }

    @Test
    fun `should return empty list when user has no call history`() {
        // given
        whenever(callRepository.findByCallerId("user-A")).thenReturn(emptyList())
        whenever(callRepository.findByReceiverId("user-A")).thenReturn(emptyList())

        // when
        val result = callService.getCallHistory("user-A")

        // then
        assertThat(result).isEmpty()
    }
